url_options.data:
{
  "size": 0,
  "query": {
    "bool": {
      "filter": [
        {
          "range": {
            "@timestamp": {
              "gte": "${__from}",
              "lte": "${__to}"
            }
          }
        },
        { "wildcard": { "session.media.id": "${media_id}" } },
        { "wildcard": { "session.player.platform": "${platform}" } },
        { "terms": { "event_name": ["ERROR", "START"] } }
      ]
    }
  },
  "aggs": {
    "web_apps": {
      "filter": {
        "bool": {
          "must_not": [
            { "terms": { "session.player.platform": ["Android", "android", "Apple"] } }
          ]
        }
      },
      "aggs": {
        "by_application": {
          "terms": {
            "field": "session.media.short_origin",
            "size": 500
          },
          "aggs": {
            "errors": {
              "filter": {
                "bool": {
                  "filter": [
                    { "term": { "event_name": "ERROR" } },
                    { "term": { "data.business_error": false } }
                  ],
                  "must_not": [
                    { "terms": { "data.error_type": ["DRM_NOT_SUPPORTED", "CONNECTION_ERROR"] } }
                  ]
                }
              }
            },
            "starts": {
              "filter": { "term": { "event_name": "START" } }
            },
            "error_rate": {
              "bucket_script": {
                "buckets_path": { "err": "errors>_count", "sess": "starts>_count" },
                "script": "params.sess > 0 ? params.err / params.sess : 0"
              }
            },
            "p50_load_time": {
              "filter": { "term": { "event_name": "START" } },
              "aggs": {
                "percentile": {
                  "percentiles": {
                    "field": "session.qoe_timings.total",
                    "percents": [50]
                  }
                }
              }
            }
          }
        }
      }
    },

    "mobile_apps": {
      "filter": {
        "terms": { "session.player.platform": ["Android", "android", "Apple"] }
      },
      "aggs": {
        "by_application": {
          "terms": {
            "field": "session.application.id",
            "size": 500
          },
          "aggs": {
            "errors": {
              "filter": {
                "bool": {
                  "filter": [
                    { "term": { "event_name": "ERROR" } },
                    { "term": { "data.business_error": false } }
                  ],
                  "must_not": [
                    { "terms": { "data.error_type": ["DRM_NOT_SUPPORTED", "CONNECTION_ERROR"] } }
                  ]
                }
              }
            },
            "starts": {
              "filter": { "term": { "event_name": "START" } }
            },
            "error_rate": {
              "bucket_script": {
                "buckets_path": { "err": "errors>_count", "sess": "starts>_count" },
                "script": "params.sess > 0 ? params.err / params.sess : 0"
              }
            },
            "p50_load_time": {
              "filter": { "term": { "event_name": "START" } },
              "aggs": {
                "percentile": {
                  "percentiles": {
                    "field": "session.qoe_timings.total",
                    "percents": [50]
                  }
                }
              }
            }
          }
        }
      }
    }
  }
}

